using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Fix 1: Preserve legacy discriminator property name for existing documents
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Fix 2: Preserve legacy "EntityType|Key" id format for existing documents
        modelBuilder.Entity<Blog>().HasPartitionKey(b => b.Id);
        modelBuilder.Entity<Blog>().Property(b => b.Id)
            .HasJsonPropertyName("id");
        modelBuilder.Entity<Blog>().UsePropertyAccessMode(PropertyAccessMode.Property);

        // Fix 3: Remove HasIndex — not supported in EF Core 9 Cosmos provider
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // Fix 2: Restore the legacy id format "EntityType|Key"
        configurationBuilder.Conventions.Add(_ => new IdFormatConvention());
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

