using Microsoft.EntityFrameworkCore;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        var blog = modelBuilder.Entity<Blog>();

        // Breaking change 1: Discriminator property renamed from "Discriminator" to "$type".
        // Fix: explicitly set the old property name so existing documents are still found.
        blog.HasDiscriminator<string>("Discriminator")
            .HasValue<Blog>("Blog");

